 {"id":"charmed_rust-rao","title":"[Bench] Create bubbletea benchmarks (message dispatch, event loop)","description":"# Task: Create bubbletea Benchmarks (Message Dispatch, Event Loop)

## Parent Epic
charmed_rust-0p1: Add Comprehensive Benchmark Suite

## Objective
Benchmark the core bubbletea runtime including message dispatch, event loop overhead, command execution, and key parsing - critical paths that run on every user interaction.

## Detailed Requirements

### 1. Message Dispatch Benchmarks
```rust
use criterion::{black_box, criterion_group, Criterion, Throughput};
use bubbletea::{Model, Cmd};

// Simple model for benchmarking
struct BenchModel {
    count: i32,
}

enum BenchMsg {
    Increment,
    Decrement,
    NoOp,
}

impl Model for BenchModel {
    type Message = BenchMsg;

    fn init(&self) -> Cmd<Self::Message> { Cmd::none() }

    fn update(&mut self, msg: Self::Message) -> Cmd<Self::Message> {
        match msg {
            BenchMsg::Increment => self.count += 1,
            BenchMsg::Decrement => self.count -= 1,
            BenchMsg::NoOp => {},
        }
        Cmd::none()
    }

    fn view(&self) -> String {
        format!("Count: {}", self.count)
    }
}

fn bench_message_dispatch(c: &mut Criterion) {
    let mut group = c.benchmark_group("bubbletea/message_dispatch");

    group.bench_function("single_message", |b| {
        let mut model = BenchModel { count: 0 };
        b.iter(|| {
            black_box(model.update(BenchMsg::Increment))
        })
    });

    group.throughput(Throughput::Elements(1000));
    group.bench_function("1000_messages", |b| {
        b.iter(|| {
            let mut model = BenchModel { count: 0 };
            for _ in 0..1000 {
                model.update(BenchMsg::Increment);
            }
            black_box(model.count)
        })
    });

    group.finish();
}
```

### 2. View Rendering Benchmarks
```rust
fn bench_view_rendering(c: &mut Criterion) {
    let mut group = c.benchmark_group("bubbletea/view");

    // Simple view
    group.bench_function("simple_view", |b| {
        let model = BenchModel { count: 42 };
        b.iter(|| black_box(model.view()))
    });

    // Complex view with styling
    struct ComplexModel {
        items: Vec<String>,
        selected: usize,
    }

    impl Model for ComplexModel {
        type Message = ();
        fn init(&self) -> Cmd<()> { Cmd::none() }
        fn update(&mut self, _: ()) -> Cmd<()> { Cmd::none() }
        fn view(&self) -> String {
            let mut s = String::with_capacity(self.items.len() * 50);
            for (i, item) in self.items.iter().enumerate() {
                if i == self.selected {
                    s.push_str("> ");
                } else {
                    s.push_str("  ");
                }
                s.push_str(item);
                s.push('\n');
            }
            s
        }
    }

    let model = ComplexModel {
        items: (0..100).map(|i| format!("Item {}", i)).collect(),
        selected: 50,
    };

    group.bench_function("list_100_items", |b| {
        b.iter(|| black_box(model.view()))
    });

    group.finish();
}
```

### 3. Key Parsing Benchmarks
```rust
fn bench_key_parsing(c: &mut Criterion) {
    let mut group = c.benchmark_group("bubbletea/key_parsing");

    // Simple key
    group.bench_function("simple_key", |b| {
        let input = b"a";
        b.iter(|| black_box(bubbletea::parse_key(input)))
    });

    // Arrow key (escape sequence)
    group.bench_function("arrow_key", |b| {
        let input = b"\x1b[A"; // Up arrow
        b.iter(|| black_box(bubbletea::parse_key(input)))
    });

    // Ctrl+key
    group.bench_function("ctrl_key", |b| {
        let input = b"\x03"; // Ctrl+C
        b.iter(|| black_box(bubbletea::parse_key(input)))
    });

    // F-key
    group.bench_function("f_key", |b| {
        let input = b"\x1bOP"; // F1
        b.iter(|| black_box(bubbletea::parse_key(input)))
    });

    // Unicode
    group.bench_function("unicode_key", |b| {
        let input = "🦀".as_bytes();
        b.iter(|| black_box(bubbletea::parse_key(input)))
    });

    group.finish();
}
```

### 4. Command Execution Benchmarks
```rust
fn bench_commands(c: &mut Criterion) {
    let mut group = c.benchmark_group("bubbletea/commands");

    group.bench_function("Cmd::none", |b| {
        b.iter(|| black_box(Cmd::<()>::none()))
    });

    group.bench_function("Cmd::batch_10", |b| {
        let cmds: Vec<Cmd<()>> = (0..10).map(|_| Cmd::none()).collect();
        b.iter(|| black_box(Cmd::batch(cmds.clone())))
    });

    group.bench_function("Cmd::message", |b| {
        b.iter(|| black_box(Cmd::message(BenchMsg::NoOp)))
    });

    group.finish();
}
```

### 5. Event Loop Simulation
```rust
fn bench_event_loop(c: &mut Criterion) {
    let mut group = c.benchmark_group("bubbletea/event_loop");

    // Simulate 1 frame cycle
    group.bench_function("frame_cycle", |b| {
        let mut model = BenchModel { count: 0 };
        b.iter(|| {
            // Typical frame: update, view, render
            let _ = model.update(BenchMsg::Increment);
            let view = model.view();
            black_box(view)
        })
    });

    // Simulate 60fps for 1 second
    group.throughput(Throughput::Elements(60));
    group.bench_function("60fps_1sec", |b| {
        b.iter(|| {
            let mut model = BenchModel { count: 0 };
            for _ in 0..60 {
                model.update(BenchMsg::Increment);
                black_box(model.view());
            }
        })
    });

    group.finish();
}
```

